mapper.select:
SELECT *
FROM t_car_cost_basic_info
WHERE waybill_id = #{waybillId} and confirm_flag = #{confirmFlag}

mapper.update:
UPDATE t_car_cost_basic_info
SET confirm_flag = #{confirmFlag}
WHERE basic_info_id = #{basicInfoId}

mapper.select:
SELECT confirm_flag
FROM t_car_cost_basic_info
WHERE waybill_id = #{waybillId}

SELECT vehicle_id, SUM( high_speed_mileage ) high_speed_mileage, SUM( low_speed_mileage ) low_speed_mileage, SUM( gps_mileage ) gps_mileage, SUM( oil_consumption ) oil_consumption FROM t_car_cost_basic_info ccbi LEFT JOIN t_waybill w ON w.waybill_id = ccbi.waybill_id where DATE_FORMAT(w.create_time, '%Y-%m-%d') >= #{queryForm.startTime} AND DATE_FORMAT(w.create_time, '%Y-%m-%d') <= #{queryForm.endTime} and ccbi.enterprise_id = #{queryForm.enterpriseId} and vehicle_id in
#{item}
GROUP BY vehicle_id

SELECT ccbi.*, w.waybill_number, w.container_number, v.vehicle_number, d.driver_name FROM t_car_cost_basic_info ccbi LEFT JOIN t_waybill w ON w.waybill_id = ccbi.waybill_id LEFT JOIN t_vehicle v ON v.vehicle_id = w.vehicle_id LEFT JOIN t_driver d ON d.driver_id = w.driver_id
AND w.driver_id = #{queryForm.driverId}
AND w.vehicle_id = #{queryForm.vehicleId}
AND ccbi.confirm_flag = #{queryForm.confirmFlag}
AND INSTR(w.waybill_number, #{queryForm.waybillNumber})
AND INSTR(w.container_number, #{queryForm.containerNumber})
ORDER BY ccbi.create_time DESC
